import React from 'react';


// 1. Importa o novo arquivo de dados unificado
import { legalContent } from 'data/legalContent'; 

// Importa o estilo compartilhado


const PrivacyPolicyPage = () => {
  return (
    <>

      <main>
        <div className="container">
          <div className="text-content-page">
            {/* --- SEÇÃO POLÍTICA DE PRIVACIDADE --- */}
            <h1>{legalContent.privacyPolicy.title}</h1>
            <p className="last-updated">{legalContent.privacyPolicy.lastUpdated}</p>
            {legalContent.privacyPolicy.sections.map((section, index) => (
              <React.Fragment key={`privacy-${index}`}>
                <h2>{section.title}</h2>
                {section.content}
              </React.Fragment>
            ))}

            {/* --- SEÇÃO TERMOS DE USO --- */}
            {/* Adicionamos o ID aqui para criar a "âncora" */}
            <h1 id={legalContent.termsOfUse.anchorId} style={{ marginTop: '5rem' }}>
              {legalContent.termsOfUse.title}
            </h1>
            <p className="last-updated">{legalContent.termsOfUse.lastUpdated}</p>
            {legalContent.termsOfUse.sections.map((section, index) => (
              <React.Fragment key={`terms-${index}`}>
                <h2>{section.title}</h2>
                {section.content}
              </React.Fragment>
            ))}
          </div>
        </div>
      </main>

    </>
  );
};

export default PrivacyPolicyPage;
